INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$550+ design blocks$q$, $q$A large library of professionally designed, responsive content blocks for headers, galleries, pricing, and more, assembled like a page layout tool.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Zero Block freeform editor$q$, $q$A pixel-level design canvas for building fully custom sections beyond the standard block grid, without writing code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Built-in SEO controls$q$, $q$Per-page meta titles, descriptions, Open Graph tags, redirects, and clean URL structures for organic search visibility.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Native e-commerce$q$, $q$Product catalogs, shopping cart, and payment gateway integrations for running a small online store directly on Tilda.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Source code export$q$, $q$Business plan subscribers can export static HTML/CSS, giving an exit path other closed-platform builders typically lack.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Responsive design engine$q$, $q$Every block automatically adapts across desktop, tablet, and mobile breakpoints with per-device fine-tuning.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Custom domains and SSL$q$, $q$Connect a custom domain with free SSL on paid plans, plus support for DNS configuration and email forwarding.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Online course tools$q$, $q$Basic tools for structuring and selling simple digital courses or membership content directly from a Tilda site.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Produces visually polished, magazine-quality pages quickly, even for non-designers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Genuinely usable free plan and low-cost entry-level paid tier compared to many competitors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Source code export on the Business plan is rare among no-code website builders$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Strong built-in SEO controls for a no-code tool$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Zero Block gives advanced users freeform design flexibility without leaving the platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Block-based approach can feel restrictive for users wanting a completely blank canvas$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$E-commerce features are basic compared to dedicated platforms like Shopify$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Free and Personal plans limit users to a single website$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Fewer native third-party app integrations than larger builders like Wix$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Monthly (non-annual) billing carries a noticeable price premium$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$What is Tilda used for?$q$, $q$Tilda is used to build landing pages, marketing and corporate websites, blogs, portfolios, small online stores, and simple online courses without writing code.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Is Tilda free?$q$, $q$Yes, Tilda has a free plan that allows building one website with a limited set of basic blocks. Full features require a paid Personal or Business plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$How much does Tilda cost?$q$, $q$The Personal plan starts at $10 per month billed annually (or $15 monthly), and the Business plan starts at $20 per month billed annually (or $25 monthly).$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Who founded Tilda?$q$, $q$Tilda was founded in 2014 by designer and entrepreneur Nikita Obukhov, originally in Moscow, Russia.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Can I export my Tilda website's code?$q$, $q$Yes, on the Business plan users can export a site's HTML and CSS source code, which most closed no-code builders do not allow.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Does Tilda support e-commerce?$q$, $q$Yes, Tilda includes native product catalogs, a shopping cart, and payment integrations suitable for small online stores.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$How is Tilda different from Wix or Squarespace?$q$, $q$Tilda emphasizes editorial, block-based layouts and offers source code export on paid plans, while Wix and Squarespace lean more toward freeform canvases and closed hosting with no code export.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Is Tilda good for SEO?$q$, $q$Tilda includes built-in controls for meta titles, descriptions, Open Graph tags, and clean URLs, making it a reasonably strong option for SEO-conscious site owners among no-code builders.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Marketing landing pages$q$, $q$Agencies and marketers use Tilda's block library to quickly launch campaign landing pages with polished, on-brand design.$q$, $q$Marketers and agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Portfolio and personal sites$q$, $q$Designers, photographers, and freelancers use Zero Block and the block library to build visually distinctive personal or portfolio sites.$q$, $q$Freelancers and creatives$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Small online stores$q$, $q$Small business owners use Tilda's built-in e-commerce blocks to sell a limited product catalog without adopting a separate storefront platform.$q$, $q$Small business owners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["1 website","Basic content blocks","Tilda subdomain","Made on Tilda branding"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Personal$q$, $q$$10/month (annual) or $15/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["1 website","Full block library","Custom domain","Online store and course features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$Business$q$, $q$$20/month (annual) or $25/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Up to 5 websites","Everything in Personal","Source code export","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$overview$q$, $q$What Is Tilda$q$, 2, ARRAY[$q$Tilda is a no-code website builder that replaces the typical drag-and-drop canvas with a library of pre-designed content blocks. Instead of positioning individual elements freely, users stack and customize blocks for headers, image galleries, pricing tables, testimonials, and forms, which produces visually consistent, editorial-style pages faster than traditional builders. The company was founded in 2014 by designer and entrepreneur Nikita Obukhov in Moscow and has since grown into a globally used platform with a registered operating headquarters in London.$q$, $q$The platform is aimed at people who care about visual design but do not want to code: marketers, small business owners, freelance designers, agencies, and content creators. Tilda is used to build landing pages, corporate websites, blogs, online stores, digital magazines, and simple online courses. Its most distinctive feature is 'Zero Block,' a pixel-level freeform editor layered on top of the block system that lets more advanced users break out of the grid for fully custom designs while still benefiting from Tilda's hosting, SEO tools, and responsive engine.$q$, $q$Because pages are built from vetted design blocks rather than a blank canvas, Tilda tends to produce more visually cohesive results for non-designers than fully open canvas tools, at the cost of some layout flexibility compared to code-based development or highly flexible builders.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Tilda ships with over 550 ready-made content blocks covering headers, galleries, feature grids, pricing tables, forms, maps, and footers, all of which are responsive by default across desktop, tablet, and mobile. The Zero Block editor adds pixel-precise, freeform design control for users who want to move beyond the standard block grid without writing HTML or CSS.$q$, $q$Built-in SEO tools let users edit meta titles, descriptions, Open Graph tags, and URL structures per page, and the platform supports custom domains, SSL, and basic analytics integrations (Google Analytics, Facebook Pixel, and similar tracking tools). Tilda also includes native e-commerce functionality: product catalogs, a shopping cart, and integrations with payment providers, which makes it viable for small online stores without a separate platform.$q$, $q$On the Business plan, Tilda allows exporting a site's HTML/CSS source code, a feature most closed website builders (like Wix or Squarespace) do not offer, giving teams an exit path if they later want to host the static code elsewhere or hand it to developers for further customization.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Tilda's Free plan allows building one website with access to a limited set of basic blocks, useful for testing the platform or building a very simple page. The Personal plan costs $10 per month when billed annually (or $15 per month billed monthly) and unlocks the full block library, a custom domain, and all core platform features for a single site. The Business plan costs $20 per month billed annually (or $25 per month billed monthly) and supports up to five websites plus source code export.$q$, $q$All paid plans support Tilda's online store and course features, and annual subscribers can remove the 'Made on Tilda' footer branding. There is no enterprise or usage-based tier; pricing scales primarily by number of sites rather than by traffic or team size, which makes Tilda comparatively predictable for small teams and freelancers managing several client sites.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6ad7c247-5d9a-4f7e-b32d-198c140b1f0b', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$No-code chatbot builder$q$, $q$Design AI-powered conversation flows visually without writing code, including conditional logic and escalation rules.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$AI agents and knowledge bases$q$, $q$Connect chatbots to knowledge base content so AI agents can answer questions using a company's own documentation.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Live chat with bot handoff$q$, $q$Human agents can seamlessly take over any bot conversation from a shared team inbox.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Multichannel messaging$q$, $q$Unify conversations from a website widget, WhatsApp, Facebook Messenger, and Telegram in one dashboard.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Open-source self-hosting$q$, $q$Run the entire Tiledesk platform on your own infrastructure using the open-source codebase published on GitHub.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Customizable chat widget$q$, $q$Style the website chat widget to match brand colors, logo, and messaging tone.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$API and webhook integrations$q$, $q$Connect Tiledesk to CRMs, help desks, and internal tools through its API and webhook support.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Conversation analytics$q$, $q$Track conversation volume, bot resolution rates, and agent performance to optimize support workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Genuine open-source, self-hostable core is uncommon among chatbot and live-chat vendors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Combines chatbot automation and live chat in a single, relatively affordable platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Multichannel support for WhatsApp, Messenger, and Telegram alongside web chat$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$No-code flow builder lowers the barrier for non-technical teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Free tier and lower entry pricing than many established live-chat competitors$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Smaller company and community than major players like Intercom or Zendesk$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Self-hosting requires development and DevOps resources to maintain$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Fewer native integrations and marketing automation features than larger incumbents$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Conversation and AI usage limits can require upgrading plans quickly for active support teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Documentation and support depth vary between the open-source and cloud versions$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$What is Tiledesk used for?$q$, $q$Tiledesk is used to build AI chatbots and combine them with live chat and multichannel messaging for customer support and sales conversations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Is Tiledesk open source?$q$, $q$Yes, Tiledesk's core platform is open source and self-hostable, published on GitHub, alongside a managed cloud version.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$How much does Tiledesk cost?$q$, $q$Tiledesk offers a free tier, with paid cloud plans starting around EUR49 per month for the Starter tier and EUR149 per month for the Pro tier; Enterprise pricing is custom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Who founded Tiledesk?$q$, $q$Tiledesk S.r.l. was founded in 2020 in Italy as a spin-off of the IT consultancy Frontiere 21, building on the earlier Chat21 open-source project started in 2017.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Can Tiledesk connect to WhatsApp?$q$, $q$Yes, Tiledesk supports multichannel messaging including WhatsApp, Facebook Messenger, and Telegram alongside its website chat widget.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Does Tiledesk support AI-powered chatbots?$q$, $q$Yes, Tiledesk lets teams connect chatbots to AI agents and knowledge bases so bots can answer questions using company-specific content.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Where is Tiledesk headquartered?$q$, $q$Tiledesk is headquartered in Soleto, in the Puglia region of southern Italy.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$What is the difference between self-hosted and cloud Tiledesk?$q$, $q$Self-hosted Tiledesk runs on a company's own infrastructure using the open-source code, while the cloud version is a managed SaaS product with subscription pricing and no infrastructure setup required.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Automated customer support$q$, $q$Support teams deploy AI chatbots to answer common questions instantly, escalating complex issues to live agents.$q$, $q$Customer support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Multichannel sales conversations$q$, $q$Sales teams use Tiledesk to manage inbound leads across web chat, WhatsApp, and Messenger from a single inbox.$q$, $q$Sales and marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Privacy-focused self-hosted deployments$q$, $q$Development teams self-host Tiledesk to keep customer conversation data on their own infrastructure for compliance reasons.$q$, $q$Developers and regulated industries$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Limited conversations","Basic chatbot builder","Live chat widget"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Starter$q$, $q$~EUR49/month$q$, $q$monthly$q$, NULL, $q$["1 user","~800 conversations/month","5 AI Agents","5 Knowledge Bases","14-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Pro$q$, $q$~EUR149/month$q$, $q$monthly$q$, NULL, $q$["5 users","50 AI Agents","10 million AI tokens/month","5,000 conversations/month","1,000 Knowledge Base items","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Unlimited users","Unlimited AI Agents","Unlimited conversations","SLA-backed support","Dedicated account manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$overview$q$, $q$What Is Tiledesk$q$, 2, ARRAY[$q$Tiledesk is an open-source customer conversation platform that combines no-code AI chatbot building with live chat and multichannel messaging. It was built by Tiledesk S.r.l., an Italian software company headquartered in Soleto, Italy, formally founded in 2020 as a spin-off of the IT consultancy Frontiere 21, though the underlying technology dates back to 2017's Chat21 open-source messaging SDK.$q$, $q$The platform lets support and sales teams design chatbot conversation flows visually, connect them to large language model-powered AI agents and knowledge bases, and seamlessly escalate conversations to human agents when a bot cannot resolve a request. Conversations can be deployed through a website widget or connected to channels such as WhatsApp, Facebook Messenger, and Telegram from a single dashboard.$q$, $q$What sets Tiledesk apart from most commercial live-chat and chatbot vendors is that its core is genuinely open source and self-hostable, published on GitHub, so development teams can run the entire stack on their own servers instead of relying solely on Tiledesk's hosted cloud service. This makes it a common choice for companies with data residency requirements or developers who want to customize the platform's behavior directly.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Tiledesk's chatbot builder is no-code, letting non-developers design conversation flows with conditional logic, and it integrates with AI agents and knowledge bases so bots can answer questions using a company's own documentation rather than generic responses. Live chat sits alongside the bot layer, with a shared inbox where human agents can take over any conversation a bot escalates.$q$, $q$The platform supports multichannel messaging, unifying conversations from a website widget, WhatsApp, Facebook Messenger, and Telegram into one agent workspace. API-based integrations and webhooks allow teams to connect Tiledesk to CRMs, help desks, and internal tools, and the customizable chat widget can be styled to match a company's branding.$q$, $q$Because the core platform is open source, teams can self-host Tiledesk for full data control, or use the managed cloud version for a faster setup without infrastructure overhead. Both deployment paths share the same chatbot and live-chat feature set.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Tiledesk's hosted cloud service includes a free tier for testing, with paid plans starting at roughly EUR49 per month for the Starter tier, which includes one user, around 800 conversations per month, and a handful of AI agents and knowledge bases, backed by a 14-day free trial. The Pro tier costs roughly EUR149 per month and raises the limits to five users, dozens of AI agents, millions of AI tokens, and thousands of monthly conversations.$q$, $q$An Enterprise tier is available at custom pricing for organizations needing unlimited users, AI agents, conversations, and knowledge base items, along with SLA-backed support and a dedicated account manager. Because the platform is also open source, teams with development resources can avoid subscription costs entirely by self-hosting the core software, trading a monthly fee for their own infrastructure and maintenance effort.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2dc99054-a142-46e9-ba1a-fcacb6132ea9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Vector and raster tile serving$q$, $q$Serves both vector tiles for modern GL-based clients and server-rendered raster tiles for legacy or GIS consumers from one style.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$GL JSON styling$q$, $q$Uses the widely adopted GL JSON style format, compatible with Mapbox mobile SDKs, MapLibre, and ArcGIS Pro.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Server-side rasterization$q$, $q$Renders vector tiles into raster PNG tiles or static images on the server using the MapLibre GL Native engine.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$OGC WMTS support$q$, $q$Exposes map layers via WMTS for compatibility with traditional GIS software like QGIS and ArcGIS.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Docker and npm deployment$q$, $q$Runs via Docker containers or npm packages, simplifying self-hosted deployment on any server.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Lightweight JS-only build$q$, $q$A pure-JavaScript version with no native dependencies for easier, more portable deployment without server-side rasterization.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Offline mapping support$q$, $q$Can serve fully offline map tiles, useful for embedded devices, field applications, or air-gapped environments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Broad client compatibility$q$, $q$Works with MapLibre GL JS, Mapbox GL JS, Leaflet, OpenLayers, and native Android/iOS SDKs.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Completely free and open source with no licensing fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Full control over map data and infrastructure through self-hosting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Supports both modern vector-tile clients and legacy raster/GIS consumers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Works entirely offline, useful for embedded or restricted-network environments$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Backed by an active open-source community and the MapTiler organization$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Requires self-hosting and server maintenance; there is no managed cloud offering built into the project itself$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Server-side rasterization depends on native dependencies that can be harder to deploy on some platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$No official commercial support without going through a third party like MapTiler$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Requires separate acquisition of vector tile data (such as OpenMapTiles extracts) to have map content to serve$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Setup and configuration require technical/DevOps familiarity compared to plug-and-play hosted map APIs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$What is TileServer GL used for?$q$, $q$TileServer GL is used to self-host vector and raster map tiles for web maps, mobile apps, and GIS software, serving as an alternative to commercial map tile APIs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Is TileServer GL free?$q$, $q$Yes, TileServer GL is free and open source under the BSD 2-Clause license, with no subscription or licensing fees from the project itself.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Who maintains TileServer GL?$q$, $q$TileServer GL is maintained primarily through the MapTiler organization on GitHub, with historical contributions from Klokan Technologies and the broader MapLibre and Mapbox open-source communities.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$What rendering engine does TileServer GL use?$q$, $q$It uses MapLibre GL Native, a C++/OpenGL rendering engine, accessed via Node.js bindings, to rasterize vector tiles server-side.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Does TileServer GL work offline?$q$, $q$Yes, because it is self-hosted software, TileServer GL can run entirely offline or on isolated networks with locally stored tile data.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$What map data does TileServer GL use?$q$, $q$It typically serves vector tiles produced by projects like OpenMapTiles, though it can serve any compatible vector or raster tile source.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$What are the system requirements for TileServer GL?$q$, $q$Node.js version 20 or above is required, with Node 24 recommended; a lightweight pure-JavaScript version is also available with no native dependencies.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$How is TileServer GL different from MapTiler's hosted services?$q$, $q$TileServer GL is free, self-hosted software requiring your own infrastructure, while MapTiler's commercial cloud and MapTiler Server products are managed, paid alternatives for teams that don't want to self-host.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Self-hosted web maps$q$, $q$Development teams run TileServer GL to serve custom-styled maps for web applications without depending on a paid third-party tile API.$q$, $q$Web developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Offline and embedded mapping$q$, $q$Organizations deploy TileServer GL on local hardware to power maps in environments with no internet access, such as field devices or vehicles.$q$, $q$GIS and embedded systems teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$GIS and enterprise mapping infrastructure$q$, $q$Enterprises and government agencies use TileServer GL alongside OpenMapTiles data to build in-house mapping infrastructure with full data control.$q$, $q$GIS professionals and enterprises$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Vector and raster tile serving","GL JSON styling support","OGC WMTS output","Docker and npm deployment","No usage limits (subject to your own infrastructure)"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$overview$q$, $q$What Is TileServer GL$q$, 2, ARRAY[$q$TileServer GL is an open-source map tile server built to host vector and raster maps styled with GL JSON, the JSON-based styling format originally defined by Mapbox and now used broadly across the open web mapping ecosystem. It was first announced at the FOSS4G 2016 conference and has been developed and maintained largely through the MapTiler organization on GitHub, with historical contributions credited to Klokan Technologies, Mapbox, and the MapLibre community. The project is licensed under the permissive BSD 2-Clause license and is free to download, modify, and self-host.$q$, $q$Unlike a hosted SaaS mapping API, TileServer GL is software that organizations run themselves, either on a cloud server, on-premises infrastructure, or entirely offline. It serves vector tiles (typically produced by projects like OpenMapTiles) directly to clients such as MapLibre GL JS, Mapbox GL JS, Leaflet, and OpenLayers for web use, and to native Android and iOS mapping SDKs for mobile apps, while also offering server-side rasterization for clients or GIS tools that require traditional raster tiles, WMTS layers, or static map images.$q$, $q$Server-side rendering is powered by MapLibre GL Native, a C++/OpenGL rendering engine accessed through Node.js bindings, which lets TileServer GL turn the same vector tile and style data into pixel-based images without requiring the client to do any GL rendering itself.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$TileServer GL serves both vector tiles and server-rendered raster tiles from a single style definition, so the same map style can power interactive vector maps in modern JS libraries and static or legacy raster consumers (like older GIS clients) simultaneously. It supports OGC WMTS output for compatibility with traditional GIS software such as QGIS and ArcGIS.$q$, $q$The project ships in two forms: a full version with native rendering dependencies for server-side rasterization, and a lightweight pure-JavaScript version with no native dependencies that runs more portably (including on platforms where compiling native modules is difficult) but does not perform server-side rasterization. Both can be run via Docker or npm.$q$, $q$Because it is self-hosted and open source, TileServer GL gives organizations full control over map data, styling, and infrastructure costs, making it a common backend for offline mapping applications, custom basemaps, and self-hosted alternatives to commercial tile APIs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$TileServer GL itself is free and open source under the BSD 2-Clause license; there is no subscription fee, tile-request pricing, or licensing cost from the project. Users only pay for the infrastructure they run it on (server or cloud compute costs) and, if desired, for source vector tile data such as OpenMapTiles extracts, which are separately licensed.$q$, $q$Organizations that prefer a managed alternative can use MapTiler's commercial hosted tile services or MapTiler Server product instead of self-hosting, but TileServer GL as a standalone open-source project remains free to run indefinitely with no vendor account required.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('60df7045-6dba-4088-8dad-1316174aa0df', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Automatic time tracking$q$, $q$Tracks work time automatically by project and task, with manual time entry also supported.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Screenshots and activity monitoring$q$, $q$Captures periodic desktop screenshots and tracks activity levels to verify active work during tracked time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Web and app usage reports$q$, $q$Logs which websites and applications employees use during work hours and classifies them as productive or unproductive.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Attendance and scheduling$q$, $q$Tracks employee schedules, attendance, breaks, and leave requests alongside time data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Payroll integration$q$, $q$Generates payroll-ready reports and integrates with payroll systems based on tracked billable hours.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Client login access$q$, $q$Lets agencies grant their own clients visibility into work logged against their projects.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$60+ integrations$q$, $q$Connects with popular project management, communication, and payroll tools to fit existing workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$AI-driven productivity insights$q$, $q$Premium-tier AI features like Benchmarks AI and Unusual Activity reports surface team performance trends and anomalies.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Deep monitoring feature set (screenshots, activity levels, app/web tracking) suited to remote workforce oversight$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Flexible pricing with add-ons that let lower tiers access select premium features$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Strong integration ecosystem with 60+ third-party tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Client login feature is useful for agencies billing external clients for tracked time$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$14-day free trial gives full access to Premium features before committing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Heavy monitoring features (screenshots, mouse/keyboard tracking) can feel invasive to employees$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Pricing is per user, which adds up quickly for larger teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Some advanced features require costly add-ons or the top-tier Premium plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Less focused on freelancer-style lightweight tracking compared to tools like Toggl Track$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Employee monitoring depth requires careful communication and policy to avoid trust issues with staff$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$What is Time Doctor used for?$q$, $q$Time Doctor is used for time tracking and employee monitoring, primarily by remote teams, outsourcing agencies, and businesses that need to verify billable hours and productivity of distributed workers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$How much does Time Doctor cost?$q$, $q$Time Doctor's Basic plan starts around $7 to $8 per user per month, Standard around $10 to $14, and Premium around $16.70 to $20, with lower rates on annual billing; Enterprise pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Who founded Time Doctor?$q$, $q$Time Doctor was founded in 2012 by Rob Rawson and Liam Martin.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Does Time Doctor take screenshots?$q$, $q$Yes, Time Doctor captures periodic screenshots of employee screens as part of its activity monitoring, with settings that can be adjusted by administrators.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Is there a free trial for Time Doctor?$q$, $q$Yes, Time Doctor offers a 14-day free trial that includes full access to Premium plan features.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$How is Time Doctor different from Toggl Track?$q$, $q$Time Doctor focuses heavily on employee monitoring with screenshots and activity tracking, while Toggl Track is a lighter-weight time tracker without surveillance-style monitoring features.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Does Time Doctor integrate with payroll systems?$q$, $q$Yes, Time Doctor integrates with payroll systems and generates payroll-ready reports based on tracked hours.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Is Time Doctor good for outsourcing and BPO companies?$q$, $q$Yes, Time Doctor is widely used by outsourcing agencies and BPOs to verify contractor billable hours and monitor remote team productivity.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Remote team productivity oversight$q$, $q$Managers use Time Doctor to monitor how distributed employees spend their work hours and identify productivity trends.$q$, $q$Remote team managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Outsourcing and contractor billing$q$, $q$Agencies and BPOs use Time Doctor to verify billable hours worked by contractors and provide clients visibility into logged time.$q$, $q$Outsourcing agencies and BPOs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Payroll and attendance tracking$q$, $q$HR and operations teams use Time Doctor's attendance, leave, and payroll integration features to streamline distributed payroll processing.$q$, $q$HR and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Basic$q$, $q$$8/user/month (monthly) or ~$6.67/user/month (annual)$q$, $q$monthly or annual$q$, NULL, $q$["Automatic time tracking","Projects and tasks","Screenshots","Timeline reports","Online/offline tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Standard$q$, $q$$14/user/month (monthly) or ~$11.67/user/month (annual)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Basic","Attendance and schedules","Time approvals","Web and app usage reports","60+ integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Premium$q$, $q$$20/user/month (monthly) or ~$16.70/user/month (annual)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Standard","Benchmarks AI","Video screen recording","SSO","Dedicated success manager","2 years historical data"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["All Premium features","Private cloud deployment","Customizable BI dashboards","Guided implementation","Custom development"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$overview$q$, $q$What Is Time Doctor$q$, 2, ARRAY[$q$Time Doctor is a time tracking and employee monitoring platform launched in 2012 by co-founders Rob Rawson and Liam Martin to help companies manage and measure the productivity of remote and distributed teams. The company itself operates as a fully distributed organization with employees spread across more than 30 countries and no central physical office, though it lists a corporate address in Las Vegas, Nevada.$q$, $q$The platform combines automatic time tracking with monitoring features such as periodic screenshots, activity level tracking, and website and application usage reports, giving managers visibility into how remote employees and contractors spend their working hours. It is widely used by outsourcing companies, BPOs, staffing agencies, and remote-first businesses that need to verify billable hours or oversee distributed contractor teams.$q$, $q$Time Doctor sits at the heavier-monitoring end of the time tracking market, alongside tools like Hubstaff, offering more surveillance-oriented features than lightweight time trackers such as Toggl Track, which appeals to companies prioritizing accountability and productivity oversight over a lighter-touch tracking experience.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Time Doctor's core feature set includes automatic and manual time tracking tied to projects and tasks, periodic desktop screenshots, and idle-time detection to flag inactive tracking sessions. Timeline reports break down a user's day by task and application, giving managers a granular view of how time was spent.$q$, $q$Higher-tier plans add attendance and schedule management, time-off tracking, payroll integration, and time approval workflows, along with web and app usage reports and productivity ratings that classify tools as productive or unproductive. The Premium plan introduces AI-driven features like Benchmarks AI (comparing performance across teams), an Unusual Activity report, mouse jiggler and clicker detection to catch tracking manipulation, and optional video screen recording.$q$, $q$Time Doctor integrates with more than 60 third-party tools including project management, payroll, and communication platforms, and offers a client login feature so agencies can give their own clients visibility into work performed on their behalf.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7ad17c3-2624-42dd-affe-a2105bd2af56', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Time Doctor prices per user per month across three core self-serve plans: Basic at roughly $7 to $8 (monthly billing) or lower on annual billing, Standard at roughly $10 to $14, and Premium at roughly $16.70 to $20, with annual billing discounted compared to month-to-month. A custom-priced Enterprise plan adds private cloud deployment, customizable BI dashboards, and guided implementation for larger organizations.$q$, $q$All plans include a 14-day free trial with full access to Premium-tier features, and ten optional add-ons (such as Benchmarks AI, video screen recording, and SSO) let Basic and Standard customers selectively add higher-tier capabilities without upgrading their whole plan.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc59330e-f844-4f93-be6c-bf6f8678410b', $q$Automatic time tracking$q$, $q$Tracks time in the background across desktop applications and websites and maps it to projects without manual timers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc59330e-f844-4f93-be6c-bf6f8678410b', $q$Free plan with unlimited users$q$, $q$A genuinely free tier supports unlimited users and projects with core timesheet functionality.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc59330e-f844-4f93-be6c-bf6f8678410b', $q$Invoicing$q$, $q$Generates client invoices directly from billable tracked hours on Starter tier and above.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc59330e-f844-4f93-be6c-bf6f8678410b', $q$Attendance and time-off tracking$q$, $q$Tracks employee attendance, overtime, and leave requests alongside time entries.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc59330e-f844-4f93-be6c-bf6f8678410b', $q$Project budgets and estimates$q$, $q$Sets and monitors project budgets and time estimates to track profitability in real time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc59330e-f844-4f93-be6c-bf6f8678410b', $q$Resource planner$q$, $q$Allocates team members' capacity across projects to balance workload and forecast availability.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc59330e-f844-4f93-be6c-bf6f8678410b', $q$Screenshot monitoring$q$, $q$Optional screenshot capture on higher tiers for verifying active work during tracked sessions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc59330e-f844-4f93-be6c-bf6f8678410b', $q$Unlimited integrations (Ultimate tier)$q$, $q$Connects with project management, accounting, and communication tools without integration limits on top plans.$q$, 7);
