-- Enrichment marathon batch: Tilda, Tiledesk, TileServer GL, Time Doctor, TimeCamp, Timely, Timescale, TimeSolv

-- ── Tilda ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tilda is a no-code website builder that uses pre-designed content blocks to let anyone create landing pages, online stores, blogs, and portfolios without writing code.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $10/month billed annually)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Russian$q$, $q$Spanish$q$, $q$Portuguese$q$]::text[],
  seo_title = COALESCE($q$Tilda Review: Pricing, Features and Alternatives (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$Tilda is a block-based no-code website builder for landing pages, stores, and blogs. See pricing, features, pros, cons, and how it compares.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tilda is a no-code website builder founded in 2014 by Nikita Obukhov in Moscow, Russia, and now operated by Tilda Publishing with a registered headquarters in London, United Kingdom. Rather than a blank canvas, Tilda is built around a library of more than 550 professionally designed content blocks that users assemble like a magazine layout, along with a freeform 'Zero Block' editor for fully custom designs. The product targets designers, marketers, small business owners, and agencies who want visually polished sites without hiring developers, and it supports landing pages, blogs, portfolios, online stores, and simple online courses. Tilda offers a genuinely usable free plan (one site, limited blocks), a Personal plan around $10 per month billed annually (single site, full block library, custom domain), and a Business plan around $20 per month billed annually (up to five sites plus HTML/CSS source code export). Monthly billing costs more than annual billing on both paid tiers. Key differentiators versus builders like Wix or Squarespace include Tilda's emphasis on editorial-style, magazine-quality layouts, built-in SEO controls (meta tags, structured data, redirects), fast static-style page delivery, and the ability to export static site code on the Business plan, which most closed-platform builders do not allow. It also includes native e-commerce tools (product catalogs, cart, and payment integrations) suitable for small stores, though it is less full-featured for commerce than dedicated platforms like Shopify. Tilda is popular in Europe and among design-conscious creators building marketing sites, one-page portfolios, and content-heavy landing pages.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6ad7c247-5d9a-4f7e-b32d-198c140b1f0b';

