-- ── Tiledesk ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tiledesk is an open-source platform for building AI chatbots and combining them with live chat, letting support teams automate conversations across web, WhatsApp, and other channels.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from approximately EUR 49/month)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Soleto, Italy$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Italian$q$]::text[],
  seo_title = COALESCE($q$Tiledesk Review: Open-Source AI Chatbot Platform Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Tiledesk is an open-source AI chatbot and live chat platform. Compare pricing, features, pros, cons, and self-hosted vs cloud options.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tiledesk is an open-source platform for building AI chatbots and blending them with human live chat agents, developed by Tiledesk S.r.l., an Italian company headquartered in Soleto, in the Puglia region of southern Italy. The company was formally founded in 2020 as a spin-off of the IT consultancy Frontiere 21, but its technical roots trace to 2017 with Chat21, an earlier open-source live messaging SDK the founding team built. Tiledesk positions itself as an 'AI Operating System' for customer conversations: teams design no-code chatbot flows and AI agents, deploy them on a website widget or channels like WhatsApp, Facebook Messenger, and Telegram, and hand conversations off to human agents when needed. A defining differentiator is that Tiledesk offers a genuinely open-source, self-hostable core (available on GitHub) alongside a hosted SaaS product, appealing to developers and privacy-conscious teams who want to run the platform on their own infrastructure rather than depend on a closed vendor. Cloud pricing starts with a free tier and paid plans beginning around EUR49 per month for a Starter tier (one user, roughly 800 conversations, a handful of AI agents and knowledge bases), scaling to a Pro tier around EUR149 per month with higher usage limits, and a custom-priced Enterprise tier with unlimited users, agents, and SLA-backed support. Compared to closed live-chat and chatbot vendors like Intercom or Drift, Tiledesk competes primarily on openness, self-hosting flexibility, and lower entry cost, while lacking the brand recognition and marketing automation depth of larger incumbents.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2dc99054-a142-46e9-ba1a-fcacb6132ea9';

