-- ── TileServer GL ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$TileServer GL is a free, open-source map tile server that hosts vector and raster maps with GL JSON styles, using server-side rendering by MapLibre GL Native.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$TileServer GL: Free Open-Source Map Tile Server Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$TileServer GL is an open-source vector and raster map tile server with GL JSON styles. Learn its features, setup, and self-hosting options.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$TileServer GL is a free, open-source map tile server for hosting vector and raster maps using GL JSON styles, with server-side raster rendering powered by MapLibre GL Native (a C++/OpenGL engine originally derived from Mapbox GL Native). It was first announced publicly at the FOSS4G 2016 conference as a project associated with Klokan Technologies, a Swiss company specializing in open-source geospatial software, and has since been maintained primarily under the MapTiler organization on GitHub (github.com/maptiler/tileserver-gl), with copyright credited across MapLibre contributors, MapTiler, Mapbox, and Klokan Technologies at various points in its history. It is licensed under the permissive BSD 2-Clause license. Unlike a commercial SaaS product, TileServer GL is not a company but a self-hosted software package: developers, GIS teams, and organizations run it on their own servers (or entirely offline) to serve map tiles for use in MapLibre GL JS, Mapbox GL JS, Leaflet, OpenLayers, and native Android/iOS mapping SDKs, as well as GIS clients via OGC WMTS. It typically consumes vector tiles produced by projects like OpenMapTiles and can rasterize them server-side into traditional PNG tiles, WMTS layers, or static map images as a fallback for clients that cannot render vector tiles directly. Because there is no vendor lock-in, licensing fee, or hosted account required, TileServer GL is popular for self-hosted mapping infrastructure, offline map deployments, and as an alternative to paid map-tile APIs from providers like Google Maps, Mapbox, or MapTiler Cloud. Node.js 20 or newer is required to run it, and it ships in both a full version (with native rendering dependencies) and a lightweight pure-JavaScript version that sacrifices server-side rasterization for easier portability.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '60df7045-6dba-4088-8dad-1316174aa0df';

