-- ── Timescale ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Timescale is the company behind TimescaleDB, an open-source time-series database built as a PostgreSQL extension, plus a managed cloud database service now marketed under the Tiger Data brand.$q$, short_description),
  pricing_model = COALESCE($q$usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free tier available; usage-based plans from ~$30/month compute$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$New York, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Timescale (TimescaleDB) Review: Pricing and Features 2026$q$, seo_title),
  seo_meta_description = COALESCE($q$Timescale is the company behind TimescaleDB, an open-source Postgres time-series database. See pricing, features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Timescale is the company behind TimescaleDB, an open-source time-series database built as an extension to PostgreSQL rather than a separate database engine, letting developers get time-series and analytics performance while keeping standard SQL and the Postgres ecosystem. The company was founded in 2015 by CEO Ajay Kulkarni and CTO Michael Freedman, who met as MIT freshmen, and is headquartered in New York City with roughly 125 employees globally. Timescale has raised approximately $180 million in total funding, including a $110 million Series C led by Tiger Global alongside Benchmark, New Enterprise Associates, Redpoint Ventures, Icon Ventures, and Two Sigma Ventures, and was valued at over $1 billion following that round; the company reports roughly 2,000 customers and mid-eight-figure annual recurring revenue. In June 2025 the company rebranded from Timescale to Tiger Data, repositioning its cloud platform as 'the modern PostgreSQL for the analytical and agentic era' while keeping TimescaleDB as the name of its open-source Postgres extension. The core TimescaleDB extension remains free and open source, giving it a large developer user base, while the company generates revenue through its managed Tiger Cloud service, enterprise support, and premium features like automatic data compression, continuous aggregates, and tiered storage. Tiger Cloud pricing is consumption-based: compute is billed hourly starting around $30/month and storage is billed per GB-month (with unlimited tiered storage on higher plans), alongside a free tier for evaluation and a custom-priced Enterprise tier with 24/7 SLAs, HIPAA compliance, and SAML SSO. TimescaleDB competes with other time-series and analytical databases like InfluxDB, ClickHouse, and QuestDB, differentiating itself by staying fully SQL-compatible and embedded within the widely adopted PostgreSQL ecosystem rather than requiring a new query language or database engine.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5979f62c-c68a-4875-ab66-878b6d196231';

